import { type DependencyList, useRef } from 'react';

export type DepsChangedEqualityFn<T> = (a: T, b: T) => boolean;

export function areDepsEqual<T extends DependencyList>(
  a: T,
  b: T,
  equalityFn: DepsChangedEqualityFn<T[number]> = Object.is
) {
  if (a === b) return true;
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) {
    if (!equalityFn(a[i], b[i])) return false;
  }
  return true;
}

export function useDepsChanged<T extends DependencyList>(
  deps: T,
  equalityFn: DepsChangedEqualityFn<T[number]> = Object.is
): boolean {
  const depsRef = useRef(deps);
  const changed = !areDepsEqual(depsRef.current, deps, equalityFn);
  depsRef.current = deps;
  return changed;
}
